#include <stdio.h>
#include <stdlib.h>
#define MAXN 700
#define MAXK 7
int max(int a, int b) { return a > b ? a : b; }
int min(int a, int b) { return a < b ? a : b; }
int abs(int a) { return a < 0 ? -a : a; }
int main() {
    int N, k;
    scanf("%d %d", &N, &k);
    int V[MAXN], B[MAXN];
    for (int i = 0; i < N; i++) {
        scanf("%d", &V[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &B[i]);
    }
    int dp[MAXN][MAXN];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            dp[i][j] = -1000000000;
        }
    }
    for (int i = 0; i < N; i++) {
        dp[i][0] = V[i];
    }
    for (int len = 2; len <= N; len++) {
        for (int i = 0; i <= N - len; i++) {
            int j = i + len - 1;
            if (B[i] == B[j] - k) {
                for (int k = i + 1; k < j; k++) {
                    dp[i][j] = max(dp[i][j], dp[i + 1][k - 1] + V[i] + V[j]);
                }
            }
        }
    }
    int ans = -1000000000;
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            ans = max(ans, dp[i][j]);
        }
    }
    printf("%d\n", ans);
    return 0;
}

